#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,a,t,sum=1,ans=1;
    cin>>n>>a;
    t=a;
    for(int i=2;i<=n;i++){
        cin>>a;
        if(a-t==1)
            sum++;
        else{
            ans=max(ans,sum);
            sum=1;
        }
        t=a;
    }
    ans=max(ans,sum);
    cout<<ans;
    return 0;
}
